import { Address, toNano, Cell } from '@ton/core';
import { Factory } from '../build/Factory/Factory_Factory';
import { NetworkProvider } from '@ton/blueprint';

export async function run(provider: NetworkProvider) {

    const AUTH_PUBKEY_HEX = process.env.AUTH_PUBKEY_HEX!;

    const pub = BigInt('0x' + AUTH_PUBKEY_HEX);
    
    const usdtMinter = Address.parse(process.env.USDT_MINTER!);
    const grcMinter = Address.parse(process.env.GRC_MINTER!);
    const notMinter = Address.parse(process.env.NOT_MINTER!);
    const pxMinter = Address.parse(process.env.PX_MINTER!);
    const dogsMinter = Address.parse(process.env.DOGS_MINTER!);

    const testJettonWalletCode = '';

    const usdtJettonWalletCode = Cell.fromHex(testJettonWalletCode);
    const grcJettonWalletCode = Cell.fromHex(testJettonWalletCode);
    const notJettonWalletCode = Cell.fromHex(testJettonWalletCode);
    const pxJettonWalletCode = Cell.fromHex(testJettonWalletCode);
    const dogsJettonWalletCode = Cell.fromHex(testJettonWalletCode);

    // const usdtJettonWalletCode = Cell.fromHex("b5ee9c72010101010023000842028f452d7a4dfd74066b682365177259ed05734435be76b5fd4bd5d8af2b7c3d68");
    // const grcJettonWalletCode = Cell.fromHex("");
    // const notJettonWalletCode = Cell.fromHex("b5ee9c7201010101002300084202ba2918c8947e9b25af9ac1b883357754173e5812f807a3d6e642a14709595395");
    // const pxJettonWalletCode = Cell.fromHex("b5ee9c7201010101002300084202ba2918c8947e9b25af9ac1b883357754173e5812f807a3d6e642a14709595395");
    // const dogsJettonWalletCode = Cell.fromHex("b5ee9c7201010101002300084202ba2918c8947e9b25af9ac1b883357754173e5812f807a3d6e642a14709595395");

    const factory = provider.open(
        await Factory.fromInit({
            $$type: 'FactoryInit',
            pub,
            usdtMinterAddress: usdtMinter,
            grcMinterAddress: grcMinter,
            notMinterAddress: notMinter,
            pxMinterAddress: pxMinter,
            dogsMinterAddress: dogsMinter,
            usdtJettonWalletCode,
            grcJettonWalletCode,
            notJettonWalletCode,
            pxJettonWalletCode,
            dogsJettonWalletCode,
        })
    );

    await factory.send(
        provider.sender(),
        {
            value: toNano('0.1'),
        },
        null
    );

    await provider.waitForDeploy(factory.address);
    console.log('Factory deployed at:', factory.address.toString());
}
